wire [(C_S00_AXI_DATA_WIDTH-1):0] slv_reg19;
wire [(C_S00_AXI_DATA_WIDTH-1):0] slv_reg20;
wire [(C_S00_AXI_DATA_WIDTH-1):0] slv_reg21;
