352	  /*
353	  // After check ila of these DEBUG signals, none of those abnormal things happen.
354	  // So the issue https://github.ugent.be/xjiao/openwifi/issues/156  root causes actually are:
355	  // 1. force_ht_smoothing is ON in our simulation/Matlab, but not (auto decided by packets from CMW). -- Check the issue comments.
356	  // 2. Two other rare cases: https://github.ugent.be/xjiao/openwifi/issues/159 and https://github.ugent.be/xjiao/openwifi/issues/158 
357	  // So the DEBUG code are not needed. Just keep them in case they are useful in the future.
358	  // DEBUG PER is higher in signaling mode. The failed IQ are successful in Matlab and Verilog sim
359	  // Try to capture 3 abnormal events:
360	  // 0. the width of iq_strobe -- normally should be 1 clk
361	  // 1. the distance between two iq_strobes -- normally should be 5 clk
362	  // 2. the distance from iq0 value change to iq_strobe
363	  // The abnormal event will be cleared by fcs_in_strobe
364	  `DEBUG_PREFIX reg iq_strobe_width_abnormal;
365	  `DEBUG_PREFIX reg iq_strobe_distance_abnormal;
366	  `DEBUG_PREFIX reg iq_strobe_distance_abnormal1;
367	  `DEBUG_PREFIX reg [2:0] iq_strobe_width_count;
368	  `DEBUG_PREFIX reg [4:0] iq_strobe_distance_count;
369	  `DEBUG_PREFIX reg [4:0] iq_change_to_iq_strobe_count;
