376	  assign iq_strobe_falling_edge = (iq_strobe_delay==1 && iq_strobe==0);
377	  assign iq_change = (iq0_delay!=iq0);
378	  always @(posedge clk) begin
379	    if (!rstn) begin
380	      iq_strobe_delay <= 0;
381	      iq0_delay <= 0;
382	    end else begin
383	      iq_strobe_delay <= iq_strobe;
384	      iq0_delay <= iq0;
385	    end
386	  end
387	
388	  // capture abnormal event
389	  always @(posedge clk) begin
390	    if (fcs_in_strobe) begin
391	      iq_strobe_width_abnormal <= 0;
392	      iq_strobe_distance_abnormal <= 0;
393	      iq_strobe_distance_abnormal1 <= 0;
394	    end else begin
395	      iq_strobe_width_abnormal <= (iq_strobe_width_count>1?1:iq_strobe_width_abnormal);
396	      iq_strobe_distance_abnormal  <= (iq_strobe_distance_count>5?1:iq_strobe_distance_abnormal);
397	      iq_strobe_distance_abnormal1 <= (iq_strobe_distance_count>4?1:iq_strobe_distance_abnormal1);
398	    end
