844	  end else begin
845	    num_dma_symbol_reg_wr_is_onging_reg <= num_dma_symbol_reg_wr_is_onging;
846	    num_dma_symbol_reg_wr_is_onging_reg1 <= num_dma_symbol_reg_wr_is_onging_reg;
847	  end
848	  end
849	
850	// select data source and mode to m_axis
851	  always @( m_axis_start_mode,m_axis_start_ext_trigger,S_AXIS_TLAST,emptyn_to_pl,data_to_pl,side_info,side_info_valid,m_axis_start_auto_trigger)//,data_transfer_control)
852	  begin
853	      case (m_axis_start_mode)
854	        2'b00 : begin // loop back from s_axis
855	                  m_axis_start_1trans_reg = S_AXIS_TLAST;
856	                  data_to_ps_reg = data_to_pl;
857	                  data_to_ps_valid_reg = emptyn_to_pl;
858	                  pl_ask_data_reg = 1;
859	                end
860	        2'b01 : begin
861	                  m_axis_start_1trans_reg = m_axis_start_auto_trigger;
862	                  data_to_ps_reg = side_info;
863	                  data_to_ps_valid_reg = side_info_valid;
864	                  pl_ask_data_reg = 0;
865	                end
866	        2'b10 : begin
867	                  m_axis_start_1trans_reg = m_axis_start_ext_trigger;
868	                  data_to_ps_reg = side_info;
869	                  data_to_ps_valid_reg = side_info_valid;
870	                  pl_ask_data_reg = 0;
871	                end
872	        2'b11 : begin
873	                  // m_axis_start_1trans_reg = m_axis_start_ext_trigger;
874	                  // data_to_ps_reg = data_to_pl;
875	                  // data_to_ps_valid_reg = (pl_ask_data&emptyn_to_pl);
876	                  // pl_ask_data_reg = data_transfer_control;
877	                  m_axis_start_1trans_reg = 0;
878	                  data_to_ps_reg = 0;
879	                  data_to_ps_valid_reg = 0;
880	                  pl_ask_data_reg = 0;
881	                end
882	      endcase
883	  end
884	
885		endmodule
